DESCRIPTION = 'ダイエット・筋トレ・健康維持の目的と予算から最適なジムを無料診断。月謝・設備・立地で比較。'
JS_CODE = 'var Qs = [\n  { text:"運動の主な目的は？", opts:["ダイエット・体型改善","筋肉をつけたい（筋トレ）","健康維持・体力づくり","競技力向上・スポーツ上達"], key:"goal" },\n  { text:"現在の運動経験は？", opts:["ほぼ未経験（これから始める）","少し経験あり","ある程度継続してきた","かなり経験がある"], key:"exp" },\n  { text:"月額予算は？", opts:["〜5,000円","5,000〜15,000円","15,000〜30,000円","30,000円以上"], key:"budget" },\n  { text:"週に通える頻度は？", opts:["週1回","週2〜3回","週4回以上","毎日でも通いたい"], key:"freq" },\n  { text:"最も重視することは？", opts:["コスパ（安く続ける）","トレーナーのサポート","設備・マシンの充実","場所・時間の便利さ"], key:"priority" }\n];\n\nvar gymTypes = {\n  personal: { emoji:"🏋️", type:"パーソナルジム", cost:"月15,000〜50,000円", desc:"専任トレーナーが1対1でサポート。短期間での体型変化を求める方に最適。", merit:"✅ 食事指導付き\\n✅ モチベーション管理\\n✅ 効率的なトレーニング" },\n  fitclub: { emoji:"🏊", type:"フィットネスクラブ", cost:"月7,000〜15,000円", desc:"プール・スタジオ・マシン室が充実した総合型ジム。多彩なプログラムを楽しめます。", merit:"✅ プール・スタジオあり\\n✅ 充実した設備\\n✅ グループレッスン" },\n  twentyfour: { emoji:"⏰", type:"24時間ジム", cost:"月3,000〜8,000円", desc:"365日24時間いつでも使えるコスパ重視のジム。セルフトレーニング派に最適。", merit:"✅ 低コスト\\n✅ 空いている時間に通える\\n✅ マシン中心" },\n  sports: { emoji:"🏃", type:"スポーツ特化型（コナミ・ルネサンス等）", cost:"月8,000〜12,000円", desc:"水泳・テニスなどスポーツ施設を備えた総合型。競技力向上にも対応。", merit:"✅ スポーツ施設充実\\n✅ コーチプログラムあり\\n✅ 家族でも利用可" }\n};\n\nvar cur=0,ans={};\n\nfunction startDiagnosis() { show(\'questions\'); renderQ(); }\n\nfunction show(name) {\n  document.querySelectorAll(\'.screen\').forEach(function(s){ s.classList.remove(\'active\'); });\n  document.getElementById(\'screen-\'+name).classList.add(\'active\');\n}\n\nfunction renderQ() {\n  var q=Qs[cur];\n  var pct=Math.round((cur+1)/Qs.length*100);\n  document.getElementById(\'q-label\').textContent=\'質問 \'+(cur+1)+\' / \'+Qs.length;\n  document.getElementById(\'q-pct\').textContent=pct+\'%\';\n  document.getElementById(\'prog\').style.width=pct+\'%\';\n  document.getElementById(\'q-text\').textContent=q.text;\n  var c=document.getElementById(\'opts\'); c.innerHTML=\'\';\n  q.opts.forEach(function(opt,i){\n    var b=document.createElement(\'button\');\n    b.className=\'option-btn\'; b.textContent=opt;\n    b.onclick=function(){ pick(i,opt,q.key); };\n    c.appendChild(b);\n  });\n}\n\nfunction pick(i,val,key) {\n  ans[key]={i:i,val:val};\n  document.querySelectorAll(\'.option-btn\').forEach(function(b,j){ b.classList.toggle(\'selected\',j===i); });\n  setTimeout(function(){\n    cur++;\n    if(cur<Qs.length){ renderQ(); } else { show(\'loading\'); setTimeout(showResults,1600); }\n  },300);\n}\n\nfunction showResults() {\n  var goalIdx=ans.goal?ans.goal.i:0;\n  var budgetIdx=ans.budget?ans.budget.i:1;\n  var priorityIdx=ans.priority?ans.priority.i:0;\n\n  var gymKey;\n  if(priorityIdx===1 || (goalIdx===0 && budgetIdx>=2)) { gymKey=\'personal\'; }\n  else if(budgetIdx===0 || priorityIdx===0) { gymKey=\'twentyfour\'; }\n  else if(goalIdx===3) { gymKey=\'sports\'; }\n  else { gymKey=\'fitclub\'; }\n\n  var gym=gymTypes[gymKey];\n  document.getElementById(\'res-emoji\').textContent=gym.emoji;\n  document.getElementById(\'res-type\').textContent=gym.type;\n  document.getElementById(\'res-cost\').textContent=gym.cost;\n  document.getElementById(\'res-desc\').textContent=gym.desc;\n  document.getElementById(\'res-merit\').innerHTML=gym.merit.replace(/\\n/g,\'<br>\');\n\n  var affArea=document.getElementById(\'affiliate-area\');\n  if(gymKey===\'personal\') {\n    affArea.innerHTML=\'<div class="bg-orange-50 border border-orange-200 rounded-xl p-4 mb-2"><div class="font-bold text-orange-800 mb-1">💪 RIZAP COOK 体験レッスン</div><p class="text-xs text-gray-600 mb-3">食事・運動を組み合わせたコミットメント型。初回無料カウンセリング実施中。</p><a href="https://px.a8.net/svt/ejp?a8mat=4B3WJ7+5UTRHM+CW6+BF23HE" rel="nofollow" target="_blank" class="block text-center bg-orange-500 text-white font-bold py-3 rounded-lg text-sm hover:bg-orange-600 transition">スコアコミット型【RIZAPゴルフ】50分無料体験 →</a><img border="0" width="1" height="1" src="https://www12.a8.net/0.gif?a8mat=4B3WJ7+5UTRHM+CW6+BF23HE" alt="" loading="lazy"><p class="text-xs text-gray-400 mt-1">※RIZAPグループ提供</p></div>\';\n  } else {\n    affArea.innerHTML=\'<div class="bg-orange-50 border border-orange-200 rounded-xl p-4 mb-2"><div class="font-bold text-orange-800 mb-1">🏋️ ジムウェア・トレーニング用品をAmazonで</div><p class="text-xs text-gray'
